import{_ as l,c as r,o as t,a5 as e,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.32：Aura 主题登场，多语言支持大升级","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.32.md","filePath":"changelog/v1.1.32.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.32.md"};function n(s,i,d,h,c,p){return t(),r("div",null,[...i[0]||(i[0]=[e('<h1 id="v1-1-32-aura-主题登场-多语言支持大升级" tabindex="-1">v1.1.32：Aura 主题登场，多语言支持大升级 <a class="header-anchor" href="#v1-1-32-aura-主题登场-多语言支持大升级" aria-label="Permalink to “v1.1.32：Aura 主题登场，多语言支持大升级”">​</a></h1><p><strong>发布日期</strong>：2026年01月22日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新带来了全新的 Aura 主题，支持阿拉伯语、挪威语、巴西葡萄牙语，新增图片渲染、会话删除等实用功能，连接可靠性大幅提升。</p><hr><h2 id="新外观-aura-主题" tabindex="-1">新外观：Aura 主题 <a class="header-anchor" href="#新外观-aura-主题" aria-label="Permalink to “新外观：Aura 主题”">​</a></h2><h3 id="aura-是什么" tabindex="-1">Aura 是什么？ <a class="header-anchor" href="#aura-是什么" aria-label="Permalink to “Aura 是什么？”">​</a></h3><p>Aura 是一个全新的主题风格，为 OpenCode 提供了一种独特的视觉体验。如果你喜欢不同的代码配色风格，现在有了一个新的选择！</p><h3 id="如何切换" tabindex="-1">如何切换？ <a class="header-anchor" href="#如何切换" aria-label="Permalink to “如何切换？”">​</a></h3><ol><li>打开 <strong>Settings</strong> (设置)</li><li>找到 <strong>Theme</strong> (主题)</li><li>选择 <strong>Aura</strong></li></ol><hr><h2 id="多语言支持大升级" tabindex="-1">多语言支持大升级 <a class="header-anchor" href="#多语言支持大升级" aria-label="Permalink to “多语言支持大升级”">​</a></h2><h3 id="新增语言" tabindex="-1">新增语言 <a class="header-anchor" href="#新增语言" aria-label="Permalink to “新增语言”">​</a></h3><p>现在支持更多语言，OpenCode 越来越国际化了！</p><ul><li>🇧🇷 <strong>巴西葡萄牙语</strong> (@ygorsimoes)</li><li>🇳🇴 <strong>挪威语</strong> (@Finityno)</li><li>🇸🇦 <strong>阿拉伯语</strong> (@NourEldin-Osama)</li></ul><h3 id="如何切换语言" tabindex="-1">如何切换语言？ <a class="header-anchor" href="#如何切换语言" aria-label="Permalink to “如何切换语言？”">​</a></h3><ol><li>打开 <strong>Settings</strong> (设置)</li><li>找到 <strong>Language</strong> (语言)</li><li>选择你需要的语言</li></ol><hr><h2 id="新功能-图片渲染" tabindex="-1">新功能：图片渲染 <a class="header-anchor" href="#新功能-图片渲染" aria-label="Permalink to “新功能：图片渲染”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在可以在会话中看到 AI 生成的图片了！Markdown 渲染已迁移到 Rust，性能更强。</p><h3 id="如何查看" tabindex="-1">如何查看？ <a class="header-anchor" href="#如何查看" aria-label="Permalink to “如何查看？”">​</a></h3><p>当 AI 生成或返回图片时，它们会直接显示在对话中，无需跳转。</p><hr><h2 id="新功能-删除会话" tabindex="-1">新功能：删除会话 <a class="header-anchor" href="#新功能-删除会话" aria-label="Permalink to “新功能：删除会话”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在可以删除不需要的会话了！保持你的会话列表整洁。</p><h3 id="如何删除" tabindex="-1">如何删除？ <a class="header-anchor" href="#如何删除" aria-label="Permalink to “如何删除？”">​</a></h3><p>在 Desktop 应用中：</p><ol><li>找到要删除的会话</li><li>右键点击或使用菜单</li><li>选择 <strong>Delete</strong> (删除)</li></ol><hr><h2 id="新功能-关闭项目" tabindex="-1">新功能：关闭项目 <a class="header-anchor" href="#新功能-关闭项目" aria-label="Permalink to “新功能：关闭项目”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>可以从悬停卡片直接关闭项目，管理更方便。</p><h3 id="如何关闭" tabindex="-1">如何关闭？ <a class="header-anchor" href="#如何关闭" aria-label="Permalink to “如何关闭？”">​</a></h3><ol><li>将鼠标悬停在项目上</li><li>在悬停卡片中找到关闭选项</li><li>点击关闭</li></ol><hr><h2 id="体验改进-连接可靠性提升" tabindex="-1">体验改进：连接可靠性提升 <a class="header-anchor" href="#体验改进-连接可靠性提升" aria-label="Permalink to “体验改进：连接可靠性提升”">​</a></h2><h3 id="这次更新了什么-3" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-3" aria-label="Permalink to “这次更新了什么？”">​</a></h3><ul><li>改进了桌面应用的连接可靠性</li><li>修复了 Windows 路径处理问题</li><li>修复了 NO_PROXY 环境变量语法错误</li></ul><h3 id="这有什么好处" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>OpenCode Desktop 会更稳定地保持连接，特别是在网络波动的情况下。</p><hr><h2 id="体验改进-自动滚动和消息展示" tabindex="-1">体验改进：自动滚动和消息展示 <a class="header-anchor" href="#体验改进-自动滚动和消息展示" aria-label="Permalink to “体验改进：自动滚动和消息展示”">​</a></h2><h3 id="这次更新了什么-4" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-4" aria-label="Permalink to “这次更新了什么？”">​</a></h3><ul><li>有新消息到达时自动滚动到底部</li><li>提交提示后自动滚动到底部</li><li>改进了&quot;跳到最新&quot;按钮的设计和动画</li><li>改进了会话 hover 状态的处理</li></ul><h3 id="这有什么好处-1" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-1" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>对话体验更流畅，不会错过 AI 的最新回复。</p><hr><h2 id="体验改进-可访问性增强" tabindex="-1">体验改进：可访问性增强 <a class="header-anchor" href="#体验改进-可访问性增强" aria-label="Permalink to “体验改进：可访问性增强”">​</a></h2><h3 id="这次更新了什么-5" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-5" aria-label="Permalink to “这次更新了什么？”">​</a></h3><ul><li>添加了无障碍功能翻译</li><li>改进了会话屏幕的可访问性 (@ndarilek)</li><li>修复了焦点被复制按钮抢走的问题</li></ul><h3 id="这有什么好处-2" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-2" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>使用屏幕阅读器等辅助工具的用户体验更好。</p><hr><h2 id="体验改进-字体堆栈扩展" tabindex="-1">体验改进：字体堆栈扩展 <a class="header-anchor" href="#体验改进-字体堆栈扩展" aria-label="Permalink to “体验改进：字体堆栈扩展”">​</a></h2><h3 id="这次更新了什么-6" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-6" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>扩展了字体堆栈，包括 macOS Nerd Font 默认名称 (@bewareoftheleopard)。</p><h3 id="这有什么好处-3" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-3" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>在 macOS 上会优先使用系统默认的 Nerd Font，显示效果更一致。</p><hr><h2 id="新功能-远程目录挂载" tabindex="-1">新功能：远程目录挂载 <a class="header-anchor" href="#新功能-远程目录挂载" aria-label="Permalink to “新功能：远程目录挂载”">​</a></h2><h3 id="这次更新了什么-7" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-7" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>TUI 的 attach 命令现在允许指定远程目录 (@gricha)。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3>',66),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode attach --dir /path/to/remote/directory")])],-1),e('<hr><h2 id="新功能-终端面板自动打开" tabindex="-1">新功能：终端面板自动打开 <a class="header-anchor" href="#新功能-终端面板自动打开" aria-label="Permalink to “新功能：终端面板自动打开”">​</a></h2><h3 id="这次更新了什么-8" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-8" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>创建新终端时，会自动打开终端面板 (@kearns-cu)。</p><h3 id="这有什么好处-4" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-4" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>不需要手动切换到终端视图，提升工作效率。</p><hr><h2 id="新功能-始终显示-review-按钮" tabindex="-1">新功能：始终显示 Review 按钮 <a class="header-anchor" href="#新功能-始终显示-review-按钮" aria-label="Permalink to “新功能：始终显示 Review 按钮”">​</a></h2><h3 id="这次更新了什么-9" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-9" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>Toggle-Review 按钮现在始终可见 (@DNGriffin)。</p><h3 id="这有什么好处-5" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-5" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>更方便地切换代码审查模式。</p><hr><h2 id="技术细节更新" tabindex="-1">技术细节更新 <a class="header-anchor" href="#技术细节更新" aria-label="Permalink to “技术细节更新”">​</a></h2><h3 id="acp-接口变更" tabindex="-1">ACP 接口变更 <a class="header-anchor" href="#acp-接口变更" aria-label="Permalink to “ACP 接口变更”">​</a></h3><p><code>setSessionModel</code> 已重命名为 <code>unstable_setSessionModel</code> (@maxious)。如果你在使用这个接口，需要相应更新。</p><h3 id="venice-提示词缓存" tabindex="-1">Venice 提示词缓存 <a class="header-anchor" href="#venice-提示词缓存" aria-label="Permalink to “Venice 提示词缓存”">​</a></h3><p>为 Venice 提供商添加了提示词缓存键支持 (@dpuyosa)。</p><h3 id="litellm-代理兼容性" tabindex="-1">LiteLLM 代理兼容性 <a class="header-anchor" href="#litellm-代理兼容性" aria-label="Permalink to “LiteLLM 代理兼容性”">​</a></h3><p>包含了 noop 工具以兼容 LiteLLM 代理 (@danielfrg)。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>想尝试新主题</td><td>✅ <strong>推荐升级</strong> (Aura 主题)</td></tr><tr><td>需要多语言支持</td><td>✅ 推荐升级</td></tr><tr><td>使用 Desktop 版</td><td>✅ <strong>强烈推荐</strong> (连接性大幅提升)</td></tr><tr><td>需要图片渲染功能</td><td>✅ 推荐升级</td></tr><tr><td>需要删除会话</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',24),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),e('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Revert handling of special characters in paths and git snapshot reading logic</li><li>Revert snapshot regression fix</li><li>Ensure cat command triggers external directory permission check in Bash tool</li><li>Print MCP stderr to OpenCode log file (@karta0807913)</li><li>Write refresh tokens to OpenAI auth in Codex (@CasualDeveloper)</li><li>Add workspace startup script to projects</li><li>Ensure images are properly returned as tool results</li><li>Rename <code>setSessionModel</code> to <code>unstable_setSessionModel</code> in ACP (@maxious)</li><li>Correct spelling of &#39;supercedes&#39; to &#39;supersedes&#39; (@luojiyin1987)</li><li>Add prompt cache key support for Venice provider (@dpuyosa)</li><li>Include noop tool in activeTools for LiteLLM proxy compatibility (@danielfrg)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Allow remote directory specification in attach command (@gricha)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Add Brazilian Portuguese locale support (@ygorsimoes)</li><li>Make &#39;Learn More&#39; link functional in theme settings (@LAG-4)</li><li>Render images in session review</li><li>Fix Windows path handling in app tests</li><li>Fix new session button in app</li><li>Add translations support to app</li><li>Delete sessions</li><li>Close projects from hover card</li><li>Don&#39;t auto-navigate to workspace after reset</li><li>Expand font stacks to include macOS Nerd Font default names (@bewareoftheleopard)</li><li>Clear session hover state on navigation (@kyashrathore)</li><li>Correct NO_PROXY environment variable syntax in desktop application (@Brendonovich)</li><li>Improve desktop connection reliability (@Brendonovich)</li><li>Add terminal smoke test to app test suite</li><li>Add file viewer smoke test</li><li>Add model picker smoke test</li><li>Add smoke test for @ attachment functionality</li><li>Add slash command smoke tests to app</li><li>Settings smoke tests</li><li>Fix type error in codebase</li><li>Fix TypeScript satisfies operator usage</li><li>Fix hover card scrolling behavior</li><li>Auto-scroll to bottom when new messages arrive</li><li>Add scrollbar styling to session page (@alexyaroshuk)</li><li>Add support for Norwegian translations (@Finityno)</li><li>Snap to bottom when user submits a prompt</li><li>Add accessibility translations to the app</li><li>Change project path tooltip position to bottom in desktop app (@ProdigyRahul)</li><li>Session screen accessibility improvements (@ndarilek)</li><li>Move markdown rendering to Rust in desktop app (@nexxeln)</li><li>Add 8px left margin to sidebar toggle on desktop</li><li>Match terminal toggle button size with sidebar and review toggles</li><li>Update jump to latest button with circular design and animation</li><li>Add Arabic language support (@NourEldin-Osama)</li><li>Always show Toggle-Review button in app (@DNGriffin)</li><li>Open terminal pane when creating new terminal (@kearns-cu)</li></ul><p><strong>Thank you to 24 community contributors:</strong></p><ul><li>@R44VC0RP: <ul><li>fix: scope PR recap to only PRs from today (#9905)</li></ul></li><li>@danielfrg: <ul><li>fix: include _noop tool in activeTools for LiteLLM proxy compatibility (#9912)</li></ul></li><li>@dpuyosa: <ul><li>feat: Add promptCacheKey for Venice provider (#9915)</li></ul></li><li>@kearns-cu: <ul><li>fix(app): open terminal pane when creating new terminal (#9926)</li></ul></li><li>@luojiyin1987: <ul><li>fix: correct spelling &#39;supercedes&#39; to &#39;supersedes&#39; (#9935)</li></ul></li><li>@maxious: <ul><li>fix(acp): rename setSessionModel to unstable_setSessionModel (#9940)</li></ul></li><li>@IdrisGit: <ul><li>docs: add API server section in CONTRIBUTING.md (#9888)</li></ul></li><li>@DNGriffin: <ul><li>feat(app): always show Toggle-Review button (#9944)</li></ul></li><li>@NourEldin-Osama: <ul><li>feat(i18n): add Arabic language support (#9947)</li></ul></li><li>@nexxeln: <ul><li>refactor(desktop): move markdown rendering to rust (#10000)</li></ul></li><li>@ndarilek: <ul><li>fix(app): session screen accessibility improvements (#9907)</li></ul></li><li>@ProdigyRahul: <ul><li>fix(desktop): change project path tooltip position to bottom (#9497)</li></ul></li><li>@Finityno: <ul><li>feat: Add support for Norwegian translations (#10018)</li></ul></li><li>@alexyaroshuk: <ul><li>feat(app): add scrollbar styling to session page (#10020)</li><li>fix(ui): prevent copy buttons from stealing focus from prompt input (#10084)</li></ul></li><li>@Brendonovich: <ul><li>fix(desktop): attempt to improve connection reliability</li><li>fix(desktop): correct NO_PROXY syntax</li></ul></li><li>@kyashrathore: <ul><li>fix(app): clear session hover state on navigation (#10031)</li></ul></li><li>@ryanmiville: <ul><li>fix(app): support ctrl-n/p in lists (#10036)</li></ul></li><li>@bewareoftheleopard: <ul><li>fix(desktop): Expand font stacks to include macOS Nerd Font default names (#10045)</li></ul></li><li>@CasualDeveloper: <ul><li>fix(codex): write refresh tokens to openai auth (#10010) (#10011)</li></ul></li><li>@karta0807913: <ul><li>feat(mcp log): print mcp stderr to opencode log file (#9982)</li></ul></li><li>@LAG-4: <ul><li>fix: make &#39;Learn More&#39; link functional in theme settings (#10078)</li></ul></li><li>@shubh73: <ul><li>feat(ui): add aura theme (#10056)</li></ul></li><li>@ygorsimoes: <ul><li>feat(i18n): add br locale support (#10086)</li></ul></li><li>@gricha: <ul><li>fix(attach): allow remote --dir (#8969)</li></ul></li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const b=l(o,[["render",n]]);export{m as __pageData,b as default};
